var subarrayBitwiseORs = function(arr) {
    const res = new Set();
    let cur = new Set();
    for (const x of arr) {
        const next = new Set();
        for (const y of cur) next.add(x | y);
        next.add(x);
        cur = next;
        for (const v of cur) res.add(v);
    }
    return res.size;
};
